// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(
    localStorage.getItem("user")
  );

  const [requests, setRequests] =
    useState([]);

  const [workers, setWorkers] =
    useState([]);

  const [form, setForm] =
    useState({

      workType: "",

      labourId: "",

      labourName: "",

      location: "",

      date: ""

    });

  const jobs = [

    "Electrician",

    "Plumber",

    "Painter",

    "Carpenter",

    "Cleaner",

    "Technician",

    "Welder",

    "Driver"

  ];

  useEffect(() => {

    getRequests();

  }, []);

  // ======================
  // GET REQUESTS
  // ======================

  const getRequests = async () => {

    try {

      const res = await axios.get(

        `http://localhost:5000/api/request/customer/${user.name}`

      );

      setRequests(res.data);

    } catch (err) {

      console.log(err);

    }
  };

  // ======================
  // SEARCH WORKERS
  // ======================

  const searchWorkers =
    async (workType) => {

      try {

        const res = await axios.get(

          "http://localhost:5000/api/auth/workers"

        );

        const filtered =
          res.data.filter((worker) =>

            worker.skills.includes(
              workType
            )

          );

        setWorkers(filtered);

      } catch (err) {

        console.log(err);

      }
    };

  // ======================
  // SEND REQUEST
  // ======================

  const sendRequest =
    async () => {

      if (

        !form.workType ||

        !form.labourId ||

        !form.location ||

        !form.date

      ) {

        return alert(
          "Please fill all fields"
        );
      }

      try {

        await axios.post(

          "http://localhost:5000/api/request/send",

          {

            customerName:
              user.name,

            customerId:
              user._id,

            labourId:
              form.labourId,

            labourName:
              form.labourName,

            workType:
              form.workType,

            location:
              form.location,

            date:
              form.date,

            timings:
              ["9AM - 12PM"]

          }

        );

        alert(
          "Request Sent Successfully"
        );

        setForm({

          workType: "",

          labourId: "",

          labourName: "",

          location: "",

          date: ""

        });

        setWorkers([]);

        getRequests();

      } catch (err) {

        console.log(err);

      }
    };

  // ======================
  // CUSTOMER DECISION
  // ======================

  const customerDecision =
    async (id, decision) => {

      try {

        await axios.put(

          `http://localhost:5000/api/request/customer-decision/${id}`,

          { decision }

        );

        getRequests();

      } catch (err) {

        console.log(err);

      }
    };

  // ======================
  // FEEDBACK
  // ======================

  const submitFeedback =
    async (
      id,
      rating,
      comment
    ) => {

      if (
        !rating ||
        !comment
      ) {

        return alert(
          "Please enter rating and review"
        );
      }

      try {

        await axios.put(

          `http://localhost:5000/api/request/feedback/${id}`,

          {

            rating:
              Number(rating),

            comment

          }

        );

        alert(
          "Feedback Submitted"
        );

        getRequests();

      } catch (err) {

        console.log(err);

        alert(
          "Feedback Failed"
        );

      }
    };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* LEFT */}

        <div style={styles.leftCard}>

          <h2 style={styles.heading}>
            Hire Workers
          </h2>

          {/* WORK TYPE */}

          <select

            style={styles.input}

            value={form.workType}

            onChange={(e) => {

              setForm({

                ...form,

                workType:
                  e.target.value

              });

              searchWorkers(
                e.target.value
              );
            }}

          >

            <option value="">
              Select Work
            </option>

            {jobs.map(
              (job, index) => (

              <option
                key={index}
                value={job}
              >

                {job}

              </option>

            ))}

          </select>

          {/* WORKERS */}

          {workers.length > 0 && (

            <select

              style={styles.input}

              onChange={(e) => {

                const worker =
                  workers.find(

                    (w) =>
                      w._id ===
                      e.target.value

                  );

                setForm({

                  ...form,

                  labourId:
                    worker._id,

                  labourName:
                    worker.name

                });
              }}

            >

              <option>
                Select Worker
              </option>

              {workers.map(
                (worker) => (

                <option
                  key={worker._id}
                  value={
                    worker._id
                  }
                >

                  {worker.name}
                  {" - "}
                  {worker.city}

                </option>

              ))}

            </select>

          )}

          {/* LOCATION */}

          <input

            style={styles.input}

            placeholder="Enter Location"

            value={form.location}

            onChange={(e) =>
              setForm({

                ...form,

                location:
                  e.target.value

              })
            }

          />

          {/* DATE */}

          <input

            type="date"

            style={styles.input}

            value={form.date}

            onChange={(e) =>
              setForm({

                ...form,

                date:
                  e.target.value

              })
            }

          />

          <button

            style={styles.button}

            onClick={sendRequest}

          >

            Send Request

          </button>

        </div>

        {/* RIGHT */}

        <div style={styles.rightCard}>

          <h2 style={styles.heading}>
            My Requests
          </h2>

          {requests.length === 0 && (

            <p>
              No Requests Found
            </p>

          )}

          {requests.map((req) => (

            <div
              key={req._id}
              style={styles.requestBox}
            >

              <h3>
                {req.labourName}
              </h3>

              <p>
                Work:
                {" "}
                {req.workType}
              </p>

              <p>
                Location:
                {" "}
                {req.location}
              </p>

              <p>
                Date:
                {" "}
                {req.date}
              </p>

              <p>
                Status:
                {" "}
                {req.status}
              </p>

              <p>
                Labour Response:
                {" "}
                {req.labourResponse}
              </p>

              <p>
                Price:
                {" "}
                ₹
                {req.labourPrice}
              </p>

              <p>
                Customer Decision:
                {" "}
                {
                  req.customerDecision
                }
              </p>

              {/* ACCEPT REJECT */}

              {req.labourResponse ===
                "Accepted" &&

                req.customerDecision ===
                  "Waiting" && (

                <div
                  style={
                    styles.btnRow
                  }
                >

                  <button

                    style={
                      styles.acceptBtn
                    }

                    onClick={() =>
                      customerDecision(
                        req._id,
                        "Accepted"
                      )
                    }

                  >

                    Accept

                  </button>

                  <button

                    style={
                      styles.rejectBtn
                    }

                    onClick={() =>
                      customerDecision(
                        req._id,
                        "Rejected"
                      )
                    }

                  >

                    Reject

                  </button>

                </div>

              )}

              {/* FEEDBACK */}

              {req.customerDecision ===
                "Accepted" && (

                <div
                  style={
                    styles.feedbackSection
                  }
                >

                  <input

                    type="number"

                    min="1"

                    max="5"

                    placeholder="Enter Rating (1-5)"

                    style={styles.input}

                    onChange={(e) =>

                      setRequests(

                        requests.map(
                          (item) =>

                            item._id ===
                            req._id

                              ? {

                                  ...item,

                                  tempRating:
                                    e.target
                                      .value

                                }

                              : item

                        )

                      )
                    }

                  />

                  <textarea

                    placeholder="Write Review"

                    style={
                      styles.textarea
                    }

                    onChange={(e) =>

                      setRequests(

                        requests.map(
                          (item) =>

                            item._id ===
                            req._id

                              ? {

                                  ...item,

                                  tempComment:
                                    e.target
                                      .value

                                }

                              : item

                        )

                      )
                    }

                  />

                  <button

                    style={
                      styles.feedbackBtn
                    }

                    onClick={() =>

                      submitFeedback(

                        req._id,

                        req.tempRating,

                        req.tempComment

                      )
                    }

                  >

                    Submit Rating

                  </button>

                </div>

              )}

              {/* SHOW FEEDBACK */}

              {req.feedback &&
                req.feedback.rating > 0 && (

                <div
                  style={
                    styles.feedbackBox
                  }
                >

                  <div style={styles.starRow}>

                    {[1, 2, 3, 4, 5].map(
                      (star) => (

                      <span
                        key={star}
                        style={{

                          fontSize: "22px",

                          color:
                            req.feedback.rating >= star
                              ? "#facc15"
                              : "#d1d5db"

                        }}
                      >

                        ★

                      </span>

                    ))}

                  </div>

                  <p>
                    {
                      req.feedback
                        .comment
                    }
                  </p>

                </div>

              )}

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

